# coding: utf-8

import click
from tabulate import tabulate

from rainbow_admin.cli import err, info
from rainbow_admin.release import GrayRuleType, Release

RELEASE_HEADER = (
    "id",
    "group_id",
    "group_name",
    "version",
    "description",
    "user",
    "approval",
    "create_time",
    "status",
)


def format_release(release: Release):
    return [
        release.task_id,
        release.group.group_id,
        release.group.group_name,
        release.version_name,
        release.description,
        release.apply_user,
        release.approval_user,
        release.create_time,
        release.status,
    ]


RULE_TYPE_HEADER = ("type_id", "type_name")


def format_rule_type(rule_type: GrayRuleType):
    return [rule_type.type_id, rule_type.type_name]


@click.group(name="release")
@click.pass_context
def release_cli(ctx):
    """actions about release"""


@release_cli.command(help="list all release")
@click.option("-n", "--size", default=10, type=int)
@click.pass_context
def ls(ctx, size):
    admin = ctx.obj["admin"]
    tasks = admin.get_release_tasks(size)

    info(f"app_id={admin.app_id} release tasks::")
    click.echo(
        tabulate([format_release(v) for v in tasks], RELEASE_HEADER, tablefmt="pretty")
    )


@release_cli.command(help="all-in release task")
@click.argument("task_id", type=int, required=True)
@click.pass_context
def all_in(ctx, task_id):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    task.all_in()
    info("全量成功")


@release_cli.command(help="rollback release task")
@click.argument("task_id", type=int, required=True)
@click.pass_context
def rollback(ctx, task_id):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    task.rollback()
    info("回退成功")


@release_cli.command(help="gray release task")
@click.argument("task_id", type=int, required=True)
@click.pass_context
def gray(ctx, task_id):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    task.gray()
    info("灰度成功")


@release_cli.command(help="show all rule types")
@click.pass_context
def rule_types(ctx):
    admin = ctx.obj["admin"]
    types = admin.rule_types
    info("rule types:")
    click.echo(
        tabulate(
            [format_rule_type(v) for v in types], RULE_TYPE_HEADER, tablefmt="pretty"
        )
    )


@release_cli.command(help="get task gray rule")
@click.argument("task_id", type=int, required=True)
@click.pass_context
def get_gray_rule(ctx, task_id):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    rule = task.gray_rule()
    if rule:
        info(f"task {task_id} gray rule:")
        click.echo(f"rule_id: {rule.rule_id}")
        click.echo(f"rule_type_id: {rule.rule_type_id}")
        click.echo(f"rule_type_name: {rule.rule_type_name}")
        click.echo(f"rule_content: \n{rule.content}")
    else:
        err("未设置灰度规则")


@release_cli.command(help="set task gray rule")
@click.argument("task_id", type=int, required=True)
@click.argument("rule_type", required=True)
@click.argument("content", required=True)
@click.pass_context
def set_gray_rule(ctx, task_id, rule_type, content):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    rule_types = admin.rule_types
    valid_type = [
        i for i in rule_types if str(i.type_id) == rule_type or i.type_name == rule_type
    ]
    if not valid_type:
        err(f"未找到灰度类型：{rule_type}")
    task.set_gray_rule(valid_type[0], content)
    info("设置成功")


@release_cli.command(help="close release task")
@click.argument("task_id", type=int, required=True)
@click.pass_context
def close(ctx, task_id):
    admin = ctx.obj["admin"]
    task = admin.get_release_task(task_id)
    task.close_task()
    info("关闭成功")
